previewCss:
.darma-loader-glow-pulse {
  display: inline-block;
  width: 46px;
  height: 46px;
  border-radius: 50%;
  background: var(--loader-color, #6366f1);
  box-shadow: 0 0 0 0 color-mix(in srgb, var(--loader-color, #6366f1) 42%, transparent);
  animation: darma-loader-glow-pulse-glow 1.1s ease-in-out infinite;
}
@keyframes darma-loader-glow-pulse-glow {
  0%, 100% { transform: scale(0.9); box-shadow: 0 0 0 0 color-mix(in srgb, var(--loader-color, #6366f1) 42%, transparent); }
  50% { transform: scale(1); box-shadow: 0 0 0 18px transparent; }
}

